import{_ as e,o as l,c as a,am as d,bM as r}from"./chunks/framework.yzuB8YhR.js";const x=JSON.parse('{"title":"FastAPI 教程","description":"","frontmatter":{},"headers":[],"relativePath":"编程/Python/FastAPI/01.简介.md","filePath":"编程/Python/FastAPI/01.简介.md","lastUpdated":1776923458000}'),s={name:"编程/Python/FastAPI/01.简介.md"};function n(i,t,h,o,f,g){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="fastapi-教程" tabindex="-1">FastAPI 教程 <a class="header-anchor" href="#fastapi-教程" aria-label="Permalink to “FastAPI 教程”">​</a></h1><p><img src="'+r+'" alt="img"></p><p>FastAPI 是一个用于构建 API 的现代、快速（高性能）的 Python Web 框架，专为构建 RESTful API 而设计。</p><p>FastAPI 使用 Python 3.8+ 并基于标准的 Python 类型提示，使用 Starlette 和 Pydantic 构建，能够自动生成 API 文档并进行数据校验。</p><h2 id="谁适合阅读本教程" tabindex="-1">谁适合阅读本教程？ <a class="header-anchor" href="#谁适合阅读本教程" aria-label="Permalink to “谁适合阅读本教程？”">​</a></h2><p>本教程适合有 Python 基础的开发者学习。如果你已经了解 Python 的基本语法和类型注解，那么你将能够快速上手 FastAPI。</p><h2 id="学前需知" tabindex="-1">学前需知 <a class="header-anchor" href="#学前需知" aria-label="Permalink to “学前需知”">​</a></h2><p>学习本教程前你需要了解一些基础的 Web 知识及 <a href="https://www.runoob.com/python3/python3-tutorial.html" target="_blank" rel="noreferrer">Python 3.x 基础教程</a>。如果你对 HTTP 请求方法（GET、POST 等）不太熟悉，建议先阅读 <a href="https://www.runoob.com/http/http-tutorial.html" target="_blank" rel="noreferrer">HTTP 教程</a>。</p><hr><h2 id="fastapi-特点" tabindex="-1">FastAPI 特点 <a class="header-anchor" href="#fastapi-特点" aria-label="Permalink to “FastAPI 特点”">​</a></h2><p>FastAPI 之所以在 Python Web 框架中脱颖而出，主要得益于以下特点：</p><table tabindex="0"><thead><tr><th style="text-align:left;">特点</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>高性能</strong></td><td style="text-align:left;">基于 Starlette 和 Pydantic，性能与 NodeJS 和 Go 相当，是最快的 Python 框架之一</td></tr><tr><td style="text-align:left;"><strong>快速开发</strong></td><td style="text-align:left;">开发速度提升约 200%-300%，标准类型声明即可完成数据校验和文档生成</td></tr><tr><td style="text-align:left;"><strong>减少错误</strong></td><td style="text-align:left;">减少约 40% 的人为错误，类型系统自动捕获常见问题</td></tr><tr><td style="text-align:left;"><strong>自动文档</strong></td><td style="text-align:left;">自动生成交互式 API 文档（Swagger UI 和 ReDoc），无需手动维护</td></tr><tr><td style="text-align:left;"><strong>类型安全</strong></td><td style="text-align:left;">基于标准 Python 类型提示，编辑器提供全面的自动补全和错误检查</td></tr><tr><td style="text-align:left;"><strong>异步支持</strong></td><td style="text-align:left;">原生支持 async/await，可高效处理 IO 密集型任务</td></tr></tbody></table><hr><h2 id="fastapi-适用场景" tabindex="-1">FastAPI 适用场景 <a class="header-anchor" href="#fastapi-适用场景" aria-label="Permalink to “FastAPI 适用场景”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">场景</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">构建 API 后端</td><td style="text-align:left;">用于构建 RESTful API，支持前后端分离的 Web 应用</td></tr><tr><td style="text-align:left;">微服务架构</td><td style="text-align:left;">轻量高效，适合作为微服务后端框架</td></tr><tr><td style="text-align:left;">数据处理 API</td><td style="text-align:left;">适用于接收和返回 JSON 数据的数据处理服务</td></tr><tr><td style="text-align:left;">实时通信</td><td style="text-align:left;">支持 WebSocket，适用于实时通信场景</td></tr><tr><td style="text-align:left;">机器学习服务</td><td style="text-align:left;">可将训练好的模型封装为 API，方便前端和其他服务调用</td></tr></tbody></table><hr><h2 id="fastapi-技术栈" tabindex="-1">FastAPI 技术栈 <a class="header-anchor" href="#fastapi-技术栈" aria-label="Permalink to “FastAPI 技术栈”">​</a></h2><p>FastAPI 构建在两个核心库之上：</p><table tabindex="0"><thead><tr><th style="text-align:left;">组件</th><th style="text-align:left;">作用</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Starlette</strong></td><td style="text-align:left;">Web 框架层</td><td style="text-align:left;">提供路由、中间件、WebSocket 等基础 Web 功能，FastAPI 直接继承自 Starlette</td></tr><tr><td style="text-align:left;"><strong>Pydantic</strong></td><td style="text-align:left;">数据校验层</td><td style="text-align:left;">基于 Python 类型提示进行数据校验、序列化和文档生成</td></tr><tr><td style="text-align:left;"><strong>Uvicorn</strong></td><td style="text-align:left;">ASGI 服务器</td><td style="text-align:left;">基于 uvloop 和 httptools 的高性能 ASGI 服务器，用于运行 FastAPI 应用</td></tr></tbody></table><blockquote><p>FastAPI 是 Starlette 的子类，因此你可以使用 Starlette 的所有功能。同时 FastAPI 完全兼容 Pydantic，包括基于 Pydantic 的 ORM（如 SQLModel）等外部库。</p></blockquote><hr><h2 id="为什么选择-fastapi" tabindex="-1">为什么选择 FastAPI？ <a class="header-anchor" href="#为什么选择-fastapi" aria-label="Permalink to “为什么选择 FastAPI？”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">对比维度</th><th style="text-align:left;">FastAPI</th><th style="text-align:left;">Flask</th><th style="text-align:left;">Django</th></tr></thead><tbody><tr><td style="text-align:left;">性能</td><td style="text-align:left;">高（异步，ASGI）</td><td style="text-align:left;">中（同步，WSGI）</td><td style="text-align:left;">中（同步，WSGI）</td></tr><tr><td style="text-align:left;">自动文档</td><td style="text-align:left;">内置（Swagger UI + ReDoc）</td><td style="text-align:left;">需第三方扩展</td><td style="text-align:left;">需第三方扩展</td></tr><tr><td style="text-align:left;">类型校验</td><td style="text-align:left;">内置（Pydantic）</td><td style="text-align:left;">需手动实现</td><td style="text-align:left;">需手动实现</td></tr><tr><td style="text-align:left;">异步支持</td><td style="text-align:left;">原生支持</td><td style="text-align:left;">需扩展</td><td style="text-align:left;">3.1+ 支持</td></tr><tr><td style="text-align:left;">学习曲线</td><td style="text-align:left;">低</td><td style="text-align:left;">低</td><td style="text-align:left;">较高</td></tr><tr><td style="text-align:left;">适用规模</td><td style="text-align:left;">中小型 / 微服务</td><td style="text-align:left;">中小型</td><td style="text-align:left;">大型 / 全栈</td></tr></tbody></table><hr><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to “相关链接”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">资源</th><th style="text-align:left;">地址</th></tr></thead><tbody><tr><td style="text-align:left;">FastAPI 官方文档</td><td style="text-align:left;"><a href="https://fastapi.tiangolo.com/zh/" target="_blank" rel="noreferrer">https://fastapi.tiangolo.com/zh/</a></td></tr><tr><td style="text-align:left;">FastAPI 源码</td><td style="text-align:left;"><a href="https://github.com/tiangolo/fastapi" target="_blank" rel="noreferrer">https://github.com/tiangolo/fastapi</a></td></tr><tr><td style="text-align:left;">Starlette 文档</td><td style="text-align:left;"><a href="https://www.starlette.dev/" target="_blank" rel="noreferrer">https://www.starlette.dev/</a></td></tr><tr><td style="text-align:left;">Pydantic 文档</td><td style="text-align:left;"><a href="https://docs.pydantic.dev/" target="_blank" rel="noreferrer">https://docs.pydantic.dev/</a></td></tr></tbody></table>',26)])])}const P=e(s,[["render",n]]);export{x as __pageData,P as default};
